  ziggs: { cls: "Artillery \u00b7 Poke Mage", P: { n: "Short Fuse", d: "Periodic empowered auto that deals bonus magic damage \u2014 extra vs towers; he chips structures faster than any top laner." }, Q: { n: "Bouncing Bomb", d: "Bounces a bomb up to three times \u2014 his core long-range poke; the bounce angles let him hit you behind minions." }, W: { n: "Satchel Charge", d: "Knockback explosive that he also uses to jump walls and DEMOLISH low towers \u2014 it can shove you out of position or him out of your reach." }, E: { n: "Hexplosive Minefield", d: "Scatters mines that slow heavily and detonate on contact \u2014 zone control; walking the field is how you arrive at his R dead." }, R: { n: "Mega Inferno Bomb", d: "Huge cross-map AoE nuke \u2014 deadly on chipped targets and crashing waves; he can delete a fight from another lane." } },
  sylas: { cls: "Skirmisher \u00b7 AP Brawler", P: { n: "Petricite Burst", d: "After casting, his next auto whirls his chains for AoE bonus damage \u2014 he weaves these between every spell; the autos are half his damage." }, Q: { n: "Chain Lash", d: "Chain slam that detonates after a beat for bonus damage and a slow at the intersection \u2014 step off the X." }, W: { n: "Kingslayer", d: "Lunge that deals burst damage and HEALS him \u2014 both are stronger when he\u2019s low; diving a half-HP Sylas feeds the comeback." }, E: { n: "Abscond / Abduct", d: "Dash, then a recast chain that PULLS him to whatever it hits with a stun \u2014 his engage; the chain whiffing is your whole trade window." }, R: { n: "Hijack", d: "STEALS a copy of your ultimate and casts it with his own ratios \u2014 know what your own R does in his hands before you pick the fight." } },
  sejuani: { cls: "Vanguard \u00b7 CC Tank", P: { n: "Fury of the North", d: "Gains Frost Armor (bonus resists + slow immunity) when out of combat \u2014 your opening poke hits a much tankier target than her items say." }, Q: { n: "Arctic Assault", d: "Dash that knocks up the first enemy hit \u2014 her engage and her escape on one cooldown; punish her when it\u2019s down." }, W: { n: "Winter\u2019s Wrath", d: "Two flail arcs that stack Frost and clear waves \u2014 her main damage; each hit builds toward her E stun." }, E: { n: "Permafrost", d: "STUNS fully Frost-stacked targets \u2014 the payoff of her chain; track your own stacks and back off before the freeze." }, R: { n: "Glacial Prison", d: "Thrown bola that FREEZES the first champion hit and slows the area \u2014 her teamfight opener; the long-range catch starts everything." } },
  ryze: { cls: "Battle Mage \u00b7 Scaler", P: { n: "Arcane Mastery", d: "His spells gain power from bonus mana \u2014 he scales with mana items into a late game that out-DPSes most mages." }, Q: { n: "Overload", d: "Fast line nuke \u2014 with Flux on you it BOUNCES and powers his whole DPS pattern; his rotation lives and dies on this hitting." }, W: { n: "Rune Prison", d: "Damages and slows; ROOTS instead if you carry Flux \u2014 his lockdown; the root into Q chain is the kill threat." }, E: { n: "Spell Flux", d: "Marks targets with Flux, spreading to nearby enemies \u2014 the amp that turns his other spells lethal; minions carry it to you." }, R: { n: "Realm Warp", d: "Channels a portal that teleports his WHOLE TEAM \u2014 flanks, escapes, and cross-map collapses; a vanished Ryze is a map-wide threat." } },
  neeko: { cls: "Trickster Mage \u00b7 Burst", P: { n: "Inherent Glamour", d: "Disguises herself as a teammate, minion, or jungle plant \u2014 trust nothing that walks strangely; tab-check health bars." }, Q: { n: "Blooming Burst", d: "AoE seed that pops up to three times on hits \u2014 her core poke and burst; the re-blooms punish standing still." }, W: { n: "Shapesplitter", d: "Sends a clone while she briefly stealths \u2014 sells fakes both ways; passively every third attack deals bonus damage and speeds her up." }, E: { n: "Tangle-Barbs", d: "Skillshot ROOT that grows longer and stronger passing through targets \u2014 the last unit hit gets the longest root; never stand behind your wave." }, R: { n: "Pop Blossom", d: "After a hidden wind-up, leaps and BURSTS + STUNS everyone around her \u2014 usually arriving disguised; the crowd you didn\u2019t count is the engage." } },
  mel: { cls: "Mage \u00b7 Reflect & Execute", P: { n: "Searing Brilliance", d: "Her attacks splinter into a volley, and her spells stack Overwhelm on you \u2014 the stacks are fuel for her execute; long poke wars arm it." }, Q: { n: "Radiant Volley", d: "Fans a barrage of projectiles across an area \u2014 her core poke; each wave stacks Overwhelm." }, W: { n: "Rebuttal", d: "Briefly REFLECTS incoming projectiles back at attackers while she gains move speed \u2014 firing into it returns your own poke to your face; hold fire through the shimmer." }, E: { n: "Solar Snare", d: "A slowing zone that ROOTS targets caught in the center \u2014 her setup tool; the root into full volley is the burst pattern." }, R: { n: "Golden Eclipse", d: "Detonates ALL Overwhelm stacks on every marked enemy \u2014 an execute on anyone she has chipped; respect it once you\u2019re stacked and below half." } },
