  cassiopeia: { cls: "Battle Mage \u00b7 Sustained DPS", P: { n: "Serpentine Grace", d: "Cannot buy boots; gains move speed per LEVEL instead \u2014 she out-walks you late while holding a full item slot of extra stats." }, Q: { n: "Noxious Blast", d: "Delayed poison blast that grants her move speed on champion hit \u2014 her poke and her chase fuel in one." }, W: { n: "Miasma", d: "Poison cloud that slows and GROUNDS \u2014 no dashes or blinks inside; your mobility kit is switched off standing in it." }, E: { n: "Twin Fang", d: "Spammable nuke \u2014 cheap, fast, and HEALING her against poisoned targets; once poisoned, you\u2019re feeding her sustain." }, R: { n: "Petrifying Gaze", d: "Cone that STUNS enemies facing her and slows those turned away \u2014 the all-in flipper; turn your back on the flash-R or eat the full stun." } },
